const DEFAULT_AVATAR = "data:image/svg+xml;base64,";
const EMOJI_LIST = ['👍', '❤️', '😂', '😮', '🔥'];

function useTheme() {
  const [themeColor, setThemeColor] = useState(localStorage.getItem('themeColor') || '#5865F2');
  useEffect(() => { localStorage.setItem('themeColor', themeColor); }, [themeColor]);
  return [themeColor, setThemeColor];
}

function App() {
  const [user, loading] = useAuthState(auth);
  const [themeColor, setThemeColor] = useTheme();
  const [showAuth, setShowAuth] = useState(false);

  const userRef = user ? firestore.collection('users').doc(user.uid) : null;
  const [userDoc] = useDocumentData(userRef);

  useEffect(() => {
    if (!user || (userDoc && userDoc.banned)) return;
    const pingPresence = () => {
      userRef.set({
        uid: user.uid, email: user.email || '',
        displayName: user.displayName || (user.email ? user.email.split('@')[0] : 'Anonymous'),
        photoURL: user.photoURL || DEFAULT_AVATAR,
        lastActive: Date.now()
      }, { merge: true });
    };
    pingPresence();
    const interval = setInterval(pingPresence, 180000); // Low Cost: 3 Min Ping
    return () => clearInterval(interval);
  }, [user, userDoc, userRef]);

  if (loading) return <div style={{background: '#36393f', height: '100vh'}}></div>;

  if (userDoc && userDoc.banned) {
    return (
      <div className="signin-container" style={{flexDirection: 'column', color: 'white'}}>
        <h1 style={{color: '#ed4245'}}>Account Banned</h1>
        <p>You have been removed from the server by an administrator.</p>
        <button className="sign-in" onClick={() => auth.signOut()} style={{marginTop: '20px'}}>Log Out</button>
      </div>
    );
  }

  // Routing Logic: Render AuthScreen only if explicitly requested and user is not logged in.
  if (showAuth && !user) {
    return <AuthScreen themeColor={themeColor} goBack={() => setShowAuth(false)} />;
  }

  // Otherwise, render the Main App (User OR Guest)
  return <MainApp themeColor={themeColor} setThemeColor={setThemeColor} isGuest={!user} onLoginClick={() => setShowAuth(true)} />;
}

function AuthScreen({ themeColor, goBack }) {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleEmailAuth = async (e) => {
    e.preventDefault(); setError('');
    try {
      if (isLogin) await auth.signInWithEmailAndPassword(email, password);
      else await auth.createUserWithEmailAndPassword(email, password);
    } catch (err) { setError(err.message); }
  };

  return (
    <div className="signin-container">
      <div style={{background: '#2f3136', padding: '32px', borderRadius: '12px', width: '320px', boxShadow: '0 8px 24px rgba(0,0,0,0.2)', position: 'relative'}}>
        <button onClick={goBack} style={{position:'absolute', top:'10px', left:'10px', background:'transparent', color:'#8e9297', fontSize:'20px'}}>←</button>
        <img src={DEFAULT_AVATAR} alt="logo" style={{width: '60px', display: 'block', margin: '0 auto 10px auto'}} />
        <h2 style={{marginTop: 0, textAlign: 'center', color: '#fff'}}>{isLogin ? 'Welcome Back' : 'Create an Account'}</h2>
        <form onSubmit={handleEmailAuth} style={{display: 'flex', flexDirection: 'column', gap: '16px', padding: 0, background: 'transparent'}}>
          <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required style={{padding: '12px', borderRadius: '8px', border: 'none', background: '#202225', color: '#fff'}} />
          <button type="submit" className="sign-in" style={{display: 'block', backgroundColor: themeColor}}>{isLogin ? 'Login' : 'Sign Up'}</button>
        </form>
        {error && <p style={{color: '#ed4245', fontSize: '13px', textAlign: 'center'}}>{error}</p>}
        <p style={{textAlign: 'center', fontSize: '14px', cursor: 'pointer', color: themeColor, marginTop: '16px'}} onClick={() => setIsLogin(!isLogin)}>
          {isLogin ? 'Need an account? Register' : 'Already have an account? Login'}
        </p>
        <hr style={{borderColor: '#202225', margin: '24px 0'}} />
        <button className="sign-in" style={{width: '100%', backgroundColor: '#fff', color: '#000'}} onClick={() => auth.signInWithPopup(new firebase.auth.GoogleAuthProvider())}>Continue with Google</button>
      </div>
    </div>
  );
}

function SettingsModal({ close, themeColor, setThemeColor, isAdmin }) {
  const [activeTab, setActiveTab] = useState('account');
  const [name, setName] = useState(auth.currentUser?.displayName || '');
  const [photo, setPhoto] = useState(auth.currentUser?.photoURL || DEFAULT_AVATAR);
  const [newPassword, setNewPassword] = useState('');
  const [notificationsEnabled, setNotificationsEnabled] = useState(Notification.permission === 'granted');
  const [allUsers] = useCollectionData(firestore.collection('users'));
  const colors = ['#5865F2', '#ed4245', '#3ba55c', '#fee75c', '#eb459e', '#9b59b6'];

  const handleBase64Pfp = (e) => {
    const file = e.target.files[0];
    if(!file) return;
    if(file.size > 500000) return alert("File too large. Max 500KB.");
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 150; canvas.height = 150;
        canvas.getContext('2d').drawImage(img, 0, 0, 150, 150);
        setPhoto(canvas.toDataURL('image/jpeg', 0.8));
      };
      img.src = event.target.result;
    };
    reader.readAsDataURL(file);
  };

  const saveSettings = async () => {
    await auth.currentUser.updateProfile({ displayName: name, photoURL: photo });
    await firestore.collection('users').doc(auth.currentUser.uid).set({ displayName: name, photoURL: photo }, { merge: true });
    close();
  };

  const requestNotifications = () => {
    if (!("Notification" in window)) alert("Browser does not support notifications");
    else Notification.requestPermission().then(p => setNotificationsEnabled(p === "granted"));
  };

  return (
    <div className="settings-overlay">
      <div className="settings-layout">
        <div className="settings-sidebar">
          <div className="settings-nav">
            <h4>User Settings</h4>
            <div className={`settings-tab ${activeTab === 'account' ? 'active' : ''}`} onClick={() => setActiveTab('account')}>My Account</div>
            <div className={`settings-tab ${activeTab === 'app' ? 'active' : ''}`} onClick={() => setActiveTab('app')}>App Settings</div>
            {isAdmin && <div className={`settings-tab ${activeTab === 'admin' ? 'active' : ''}`} onClick={() => setActiveTab('admin')}>Admin Panel</div>}
            <div className="settings-divider"></div>
            <div className="settings-tab logout" onClick={() => auth.signOut()}>Log Out</div>
          </div>
        </div>
        <div className="settings-content">
          <button className="close-settings" onClick={close}>X</button>
          
          {activeTab === 'account' && (
            <>
              <h2>My Account</h2>
              <div className="settings-card">
                <div style={{display: 'flex', gap: '20px', alignItems: 'center'}}>
                  <img src={photo} alt="Preview" style={{width: '80px', height: '80px', borderRadius: '50%', objectFit: 'cover'}} />
                  <div>
                    <label className="b64-upload-btn" style={{backgroundColor: themeColor}}>
                      Upload Avatar
                      <input type="file" accept="image/*" onChange={handleBase64Pfp} />
                    </label>
                  </div>
                </div>
                <div className="settings-group" style={{marginTop:'16px'}}><label>DISPLAY NAME</label><input value={name} onChange={(e) => setName(e.target.value)} /></div>
                <button className="save-btn" onClick={saveSettings} style={{backgroundColor: themeColor, borderRadius: '8px', border: 'none'}}>Save Profile</button>
              </div>
              <div className="settings-card">
                <h3>Security</h3>
                <div className="settings-group">
                  <label>CHANGE PASSWORD</label>
                  <div style={{display: 'flex', gap: '10px'}}>
                    <input type="password" placeholder="New Password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} style={{flexGrow: 1}} />
                    <button className="save-btn" onClick={async () => {
                      try { await auth.currentUser.updatePassword(newPassword); alert('Updated!'); setNewPassword(''); } catch(e) { alert(e.message); }
                    }} style={{marginTop: 0, backgroundColor: themeColor}}>Update</button>
                  </div>
                </div>
              </div>
            </>
          )}

          {activeTab === 'app' && (
            <>
              <h2>App Settings</h2>
              <div className="settings-card">
                <h3>Theme</h3>
                <div className="color-picker">
                  {colors.map(c => <div key={c} className="color-swatch" style={{backgroundColor: c, borderColor: themeColor === c ? '#fff' : 'transparent'}} onClick={() => setThemeColor(c)} />)}
                </div>
              </div>
              <div className="settings-card">
                <div className="toggle-row" style={{padding: 0, background: 'transparent'}}>
                  <div><strong>Desktop/Mobile Notifications</strong><span>Get alerts while app is open</span></div>
                  <button onClick={requestNotifications} style={{background: notificationsEnabled ? '#3ba55c' : '#4f545c', padding: '8px 16px', color: 'white'}}>{notificationsEnabled ? 'Enabled' : 'Enable'}</button>
                </div>
              </div>
            </>
          )}

          {activeTab === 'admin' && isAdmin && (
            <>
              <h2>Admin Panel</h2>
              <div className="settings-card">
                <h3>Manage Users</h3>
                {allUsers && allUsers.map(u => (
                  <div className="ban-list-item" key={u.uid} style={{opacity: u.banned ? 0.5 : 1}}>
                    <div style={{display: 'flex', alignItems: 'center', gap: '10px'}}>
                      <img src={u.photoURL} alt="" style={{width:'30px', height:'30px', borderRadius:'50%'}} />
                      <strong style={{color: 'white'}}>{u.displayName}</strong>
                      <span style={{color: '#8e9297', fontSize: '12px'}}>{u.email}</span>
                      {u.banned && <span style={{color: '#ed4245', fontSize: '12px'}}>(Banned)</span>}
                    </div>
                    {u.email !== 'vincentr111222@gmail.com' && !u.banned && (
                      <button className="ban-btn" onClick={async () => { if(window.confirm("Ban user permanently?")) await firestore.collection('users').doc(u.uid).update({ banned: true }); }}>Ban</button>
                    )}
                  </div>
                ))}
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

function ServerSettingsModal({ server, close, themeColor }) {
  const [name, setName] = useState(server.name);
  const [icon, setIcon] = useState(server.icon || '');
  const [isPrivate, setIsPrivate] = useState(server.isPrivate || false);
  const [inviteCode, setInviteCode] = useState(server.inviteCode || '');

  const handleBase64Icon = (e) => {
    const file = e.target.files[0];
    if(!file) return;
    if(file.size > 500000) return alert("File too large. Max 500KB.");
    const reader = new FileReader();
    reader.onload = (event) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 100; canvas.height = 100;
        canvas.getContext('2d').drawImage(img, 0, 0, 100, 100);
        setIcon(canvas.toDataURL('image/jpeg', 0.8));
      };
      img.src = event.target.result;
    };
    reader.readAsDataURL(file);
  };

  const saveServer = async () => {
    let code = inviteCode;
    if (isPrivate && !code) code = Math.random().toString(36).substring(2, 8).toUpperCase();
    await firestore.collection('servers').doc(server.id).update({
      name, icon, isPrivate, inviteCode: isPrivate ? code : null,
      members: isPrivate && !server.members ? [auth.currentUser.uid] : (server.members || [])
    });
    close();
  };

  return (
    <div className="settings-overlay" style={{zIndex: 1001}}>
      <div className="server-modal-container">
        <h2 style={{margin: 0, color: '#fff'}}>Edit Server</h2>
        
        <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
          <div style={{width:'60px', height:'60px', borderRadius:'16px', background: icon.startsWith('data:') ? `url(${icon}) center/cover` : themeColor, display:'flex', justifyContent:'center', alignItems:'center', color:'white', fontWeight:'bold', fontSize:'24px'}}>
             {!icon.startsWith('data:') ? (icon || name.charAt(0).toUpperCase()) : ''}
          </div>
          <label className="b64-upload-btn" style={{backgroundColor: themeColor, margin: 0}}>
            Upload Server Icon
            <input type="file" accept="image/*" onChange={handleBase64Icon} />
          </label>
        </div>

        <div className="settings-group"><label>SERVER NAME</label><input value={name} onChange={(e) => setName(e.target.value)} style={{background: '#202225', border: 'none', padding: '12px', borderRadius: '8px', color: '#fff'}} /></div>
        <div className="toggle-row">
          <div><strong>Private Server</strong><span>Only invited members can join</span></div>
          <div className={`toggle-switch ${isPrivate ? 'on' : ''}`} onClick={() => setIsPrivate(!isPrivate)}><div className="toggle-knob"></div></div>
        </div>
        {isPrivate && <div className="settings-group"><label>INVITE CODE</label><div className="invite-code-box">{inviteCode || 'Generating...'}</div></div>}
        <div style={{display: 'flex', gap: '10px', marginTop: '10px'}}>
          <button onClick={close} style={{flex: 1, background: '#4f545c', color: 'white', padding: '12px'}}>Cancel</button>
          <button onClick={saveServer} style={{flex: 1, background: themeColor, color: 'white', padding: '12px'}}>Save</button>
        </div>
      </div>
    </div>
  )
}

function MainApp({ themeColor, setThemeColor, isGuest, onLoginClick }) {
  const [currentServer, setCurrentServer] = useState(null);
  const [currentChannel, setCurrentChannel] = useState(null);
  const [showSettings, setShowSettings] = useState(false);
  const [editingServer, setEditingServer] = useState(null);
  const [channelsOpen, setChannelsOpen] = useState(true); // PC Toggle state
  
  const isAdmin = !isGuest && auth.currentUser?.email === 'vincentr111222@gmail.com';
  const serversRef = firestore.collection('servers');
  const [allServers] = useCollectionData(serversRef.orderBy('createdAt'), { idField: 'id' });

  // Filter servers for Guests (only public) vs Users
  const servers = allServers ? allServers.filter(s => 
    isAdmin || !s.isPrivate || (!isGuest && s.members && s.members.includes(auth.currentUser?.uid))
  ) : [];

  useEffect(() => {
    if (servers && servers.length > 0 && !currentServer) setCurrentServer(servers[0]);
  }, [servers, currentServer]);

  const addServer = async () => {
    if (isGuest) return onLoginClick();
    const name = prompt("Enter Server Name:");
    if (name) await serversRef.add({ name, icon: name.charAt(0).toUpperCase(), isPrivate: false, createdAt: firebase.firestore.FieldValue.serverTimestamp() });
  };

  const joinServerViaCode = async () => {
    if (isGuest) return onLoginClick();
    const code = prompt("Enter 6-digit Invite Code:");
    if (!code) return;
    const match = allServers.find(s => s.inviteCode === code.toUpperCase());
    if (match) { await serversRef.doc(match.id).update({ members: firebase.firestore.FieldValue.arrayUnion(auth.currentUser.uid) }); alert("Joined!"); } 
    else alert("Invalid code.");
  };

  return (
    <div className="discord-layout">
      {isGuest && <div className="guest-banner">Viewing in Guest Mode — Read Only. Please log in to interact.</div>}
      
      {showSettings && !isGuest && <SettingsModal close={() => setShowSettings(false)} themeColor={themeColor} setThemeColor={setThemeColor} isAdmin={isAdmin} />}
      {editingServer && !isGuest && <ServerSettingsModal server={editingServer} close={() => setEditingServer(null)} themeColor={themeColor} />}
      
      <div className="sidebar" style={{paddingTop: isGuest ? '30px' : '12px'}}>
        {servers && servers.map(s => (
          <div key={s.id} className={`server-icon ${currentServer?.id === s.id ? 'active' : ''}`} 
               style={s.icon?.startsWith('data:') ? {backgroundImage: `url(${s.icon})`} : {}}
               onClick={() => { setCurrentServer(s); setCurrentChannel(null); }} title={s.name}>
            {!s.icon?.startsWith('data:') ? (s.icon || s.name.charAt(0).toUpperCase()) : ''}
            {isAdmin && (
              <div className="server-actions">
                <button className="action-btn edit-btn" onClick={(e) => { e.stopPropagation(); setEditingServer(s); }}>✎</button>
                <button className="action-btn del-btn-server" onClick={async (e) => { e.stopPropagation(); if(window.confirm("Delete server?")) await serversRef.doc(s.id).delete(); }}>✕</button>
              </div>
            )}
          </div>
        ))}
        {isAdmin && <div className="server-icon server-add-btn" onClick={addServer}>+</div>}
        {!isAdmin && !isGuest && <div className="server-icon server-join-btn" onClick={joinServerViaCode}>Join</div>}
      </div>

      {currentServer ? (
        <ServerContent 
          server={currentServer} 
          currentChannel={currentChannel} setCurrentChannel={setCurrentChannel} 
          isAdmin={isAdmin} isGuest={isGuest} themeColor={themeColor} 
          openSettings={() => setShowSettings(true)} onLoginClick={onLoginClick}
          channelsOpen={channelsOpen} setChannelsOpen={setChannelsOpen}
        />
      ) : (
        <div style={{flexGrow: 1, display: 'flex', justifyContent: 'center', alignItems: 'center'}}><h3 style={{color: '#8e9297'}}>No server selected.</h3></div>
      )}
    </div>
  );
}

function ServerContent({ server, currentChannel, setCurrentChannel, isAdmin, isGuest, themeColor, openSettings, onLoginClick, channelsOpen, setChannelsOpen }) {
  const dummy = useRef();
  const [formValue, setFormValue] = useState('');
  const [attachedFile, setAttachedFile] = useState(null);
  const [cooldown, setCooldown] = useState(0);
  const [mobileNav, setMobileNav] = useState(false);
  const [showMembers, setShowMembers] = useState(true);

  const channelsRef = firestore.collection(`servers/${server.id}/channels`);
  const [channels] = useCollectionData(channelsRef.orderBy('createdAt'), { idField: 'id' });
  const messagesRef = currentChannel ? firestore.collection(`servers/${server.id}/channels/${currentChannel.id}/messages`) : null;
  const [messages] = useCollectionData(messagesRef ? messagesRef.orderBy('createdAt').limit(50) : null, { idField: 'id' });
  const [allUsers] = useCollectionData(firestore.collection('users'));

  useEffect(() => {
    if (channels && channels.length === 0 && isAdmin) channelsRef.add({ name: 'general', createdAt: firebase.firestore.FieldValue.serverTimestamp() });
    if (channels && channels.length > 0 && !currentChannel) setCurrentChannel(channels[0]);
  }, [channels, currentChannel, setCurrentChannel]);

  useEffect(() => {
    let timer; if (cooldown > 0) timer = setTimeout(() => setCooldown(cooldown - 1), 1000);
    return () => clearTimeout(timer);
  }, [cooldown]);

  const handleBase64Upload = (e) => {
    if(isGuest) return onLoginClick();
    const file = e.target.files[0];
    if(!file) return;
    if(file.size > 500000) return alert("File must be under 500KB to save database writes.");
    
    const reader = new FileReader();
    reader.onload = (event) => {
      if(file.type.startsWith('image/')) {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          let width = img.width, height = img.height;
          if(width > 800) { height *= 800/width; width = 800; }
          canvas.width = width; canvas.height = height;
          canvas.getContext('2d').drawImage(img, 0, 0, width, height);
          setAttachedFile({ data: canvas.toDataURL(file.type, 0.7), type: 'image', name: file.name });
        };
        img.src = event.target.result;
      } else {
        setAttachedFile({ data: event.target.result, type: 'file', name: file.name });
      }
    };
    reader.readAsDataURL(file);
  };

  const sendMessage = async (e) => {
    e.preventDefault();
    if(isGuest) return onLoginClick();
    if ((!formValue.trim() && !attachedFile) || cooldown > 0 || !messagesRef) return;
    
    await messagesRef.add({
      text: formValue, fileData: attachedFile?.data || null, fileType: attachedFile?.type || null, fileName: attachedFile?.name || null,
      createdAt: firebase.firestore.FieldValue.serverTimestamp(),
      uid: auth.currentUser.uid, photoURL: auth.currentUser.photoURL || DEFAULT_AVATAR, 
      displayName: auth.currentUser.displayName || (auth.currentUser.email ? auth.currentUser.email.split('@')[0] : 'Anonymous')
    });

    setFormValue(''); setAttachedFile(null); setCooldown(3);
    if (dummy.current) dummy.current.scrollIntoView({ behavior: 'smooth' });
  }

  const visibleMembers = allUsers ? allUsers.filter(u => !u.banned && (!server.isPrivate || (server.members && server.members.includes(u.uid)) || isAdmin)) : [];
  const currentUserData = allUsers?.find(u => u.uid === auth.currentUser?.uid);

  return (
    <>
      {/* Mobile Channel Overlay */}
      <div className={`mobile-overlay ${mobileNav ? 'open' : ''}`} onClick={() => setMobileNav(false)}></div>
      
      {/* Left Channel Bar (Collapsible on PC & Mobile) */}
      <div className={`channels ${mobileNav ? 'open' : ''} ${!channelsOpen ? 'closed' : ''}`}>
        <div className="channels-header">
          <h3>{server.name}</h3>
          {isAdmin && <button className="add-btn" onClick={async () => { const n = prompt("Name:"); if(n) await channelsRef.add({name: n.toLowerCase()}); }}>+</button>}
        </div>
        <div className="channel-list">
          {channels && channels.map(c => (
            <div key={c.id} className={`channel ${currentChannel?.id === c.id ? 'active' : ''}`} onClick={() => {setCurrentChannel(c); setMobileNav(false);}}>
              <span className="channel-name"><span className="hash-icon">#</span> {c.name}</span>
              {isAdmin && <button className="del-btn" onClick={async (e) => { e.stopPropagation(); if(window.confirm("Delete?")) await channelsRef.doc(c.id).delete(); }}>X</button>}
            </div>
          ))}
        </div>
        <div className="user-panel">
          <div className="user-panel-info">
            <div className="avatar-container">
              <img src={isGuest ? DEFAULT_AVATAR : (currentUserData?.photoURL || DEFAULT_AVATAR)} alt="PFP" />
              {!isGuest && <div className="status-dot status-online"></div>}
            </div>
            <div><strong>{isGuest ? 'Guest' : (currentUserData?.displayName || 'Loading...')}</strong></div>
          </div>
          {!isGuest ? <button className="settings-btn" onClick={openSettings} style={{color: themeColor}}>⚙️</button> : <button className="settings-btn" onClick={onLoginClick} style={{color: themeColor, fontSize:'14px', fontWeight:'bold'}}>Log In</button>}
        </div>
      </div>

      <div className="chat-container">
        {currentChannel ? (
          <>
            <header>
              <div className="header-left">
                {/* ☰ Hamburger Button - Controls Channels Panel */}
                <button className="mobile-nav-toggle" onClick={() => { setMobileNav(!mobileNav); setChannelsOpen(!channelsOpen); }}>☰</button>
                <div className="header-title"><span className="hash-icon">#</span> {currentChannel.name}</div>
              </div>
              <button className="member-toggle" onClick={() => setShowMembers(!showMembers)} style={{color: showMembers ? themeColor : ''}}>👥</button>
            </header>
            <main>
              {messages && messages.map(msg => (
                <ChatMessage key={msg.id} message={msg} msgRef={messagesRef.doc(msg.id)} currentUserUid={auth.currentUser?.uid} isAdmin={isAdmin} isGuest={isGuest} onLoginClick={onLoginClick} />
              ))}
              <span ref={dummy}></span>
            </main>
            <div className="form-wrapper">
              {attachedFile && (
                <div className="file-preview-container">
                  {attachedFile.type === 'image' ? <img src={attachedFile.data} alt="preview" /> : <span>📎 {attachedFile.name}</span>}
                  <button onClick={() => setAttachedFile(null)}>X</button>
                </div>
              )}
              {isGuest ? (
                <div className="guest-prompt">
                  <span style={{color:'#8e9297'}}>You are viewing in Guest Mode.</span>
                  <button onClick={onLoginClick} style={{background: themeColor, padding: '10px 20px', color: 'white'}}>Login to Interact</button>
                </div>
              ) : (
                <form onSubmit={sendMessage}>
                  <label className="upload-btn" style={{color: attachedFile ? themeColor : ''}}>
                    +<input type="file" style={{display: 'none'}} onChange={handleBase64Upload} />
                  </label>
                  <input type="text" value={cooldown > 0 ? `Wait ${cooldown}s...` : formValue} onChange={(e) => setFormValue(e.target.value)} placeholder={`Message #${currentChannel.name}`} disabled={cooldown > 0} style={{opacity: cooldown > 0 ? 0.5 : 1}} />
                  <button type="submit" style={{display: 'none'}}></button>
                </form>
              )}
            </div>
          </>
        ) : ( <div style={{flexGrow: 1, display: 'flex', justifyContent: 'center', alignItems: 'center'}}><h3 style={{color: '#8e9297'}}>Select a channel</h3></div> )}
      </div>

      <div className={`member-list ${!showMembers ? 'hidden' : ''}`}>
        <div className="member-group-title">Members — {visibleMembers.length}</div>
        {visibleMembers.map(u => {
          const isOnline = (Date.now() - (u.lastActive || 0)) < 240000;
          return (
            <div className="member-item" key={u.uid}>
              <div className="avatar-container">
                <img src={u.photoURL || DEFAULT_AVATAR} alt="user" />
                <div className={`status-dot ${isOnline ? 'status-online' : 'status-offline'}`}></div>
              </div>
              <span style={{color: u.email === 'vincentr111222@gmail.com' ? '#faa61a' : ''}}>{u.displayName}</span>
            </div>
          )
        })}
      </div>
    </>
  )
}

function ChatMessage({ message, msgRef, currentUserUid, isAdmin, isGuest, onLoginClick }) {
  const { text, fileData, fileType, fileName, photoURL, displayName, uid, reactions } = message;
  
  const toggleReaction = async (emoji) => {
    if (isGuest) return onLoginClick();
    const currentReactions = reactions || {};
    const usersWhoReacted = currentReactions[emoji] || [];
    let newUsers;
    if (usersWhoReacted.includes(currentUserUid)) newUsers = usersWhoReacted.filter(id => id !== currentUserUid);
    else newUsers = [...usersWhoReacted, currentUserUid];
    
    const newReactions = { ...currentReactions };
    if (newUsers.length === 0) delete newReactions[emoji];
    else newReactions[emoji] = newUsers;
    
    await msgRef.set({ reactions: newReactions }, { merge: true });
  };

  return (
    <div className="message">
      <img className="message-avatar" src={photoURL} alt="user" />
      <div className="message-content">
        <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
          <span className="msg-author">{displayName}</span>
        </div>
        {text && <p>{text}</p>}
        {fileData && fileType === 'image' && <img src={fileData} className="msg-img" alt="attachment" onClick={() => window.open(fileData, '_blank')} />}
        {fileData && fileType === 'file' && <a href={fileData} download={fileName} className="msg-file">📎 Download {fileName}</a>}
        
        {reactions && Object.keys(reactions).length > 0 && (
          <div className="reactions-display">
            {Object.entries(reactions).map(([emoji, users]) => (
              <div key={emoji} className={`reaction-pill ${users.includes(currentUserUid) ? 'reacted' : ''}`} onClick={() => toggleReaction(emoji)}>
                {emoji} <span>{users.length}</span>
              </div>
            ))}
          </div>
        )}
      </div>
      
      {!isGuest && (
        <div className="msg-hover-actions">
          {EMOJI_LIST.map(em => <button key={em} className="react-btn" onClick={() => toggleReaction(em)}>{em}</button>)}
          {(uid === currentUserUid || isAdmin) && <button onClick={() => msgRef.delete()} style={{background: 'transparent', border: 'none', color: '#ed4245', cursor: 'pointer', fontSize: '10px', marginLeft: '4px'}}>Del</button>}
        </div>
      )}
    </div>
  )
}
export default App;
